// ResolveByName resolves a human-readable name to a UUID from synced data.
// If the input is already a UUID, it is returned as-is.
// matchFields are JSON field names to search against (e.g., "name", "key", "email").
func (s *Store) ResolveByName(resourceType string, input string, matchFields ...string) (string, error) {
	if IsUUID(input) {
		return input, nil
	}

	var matches []string
	for _, field := range matchFields {
		query := fmt.Sprintf(
			`SELECT id FROM resources WHERE resource_type = ? AND LOWER(json_extract(data, '$.%s')) = LOWER(?)`,
			field,
		)
		rows, err := s.db.Query(query, resourceType, input)
		if err != nil {
			continue
		}
		for rows.Next() {
			var id string
			if rows.Scan(&id) == nil {
				// Deduplicate
				found := false
				for _, m := range matches {
					if m == id {
						found = true
						break
					}
				}
				if !found {
					matches = append(matches, id)
				}
			}
		}
		rows.Close()
	}

	switch len(matches) {
	case 0:
		return "", fmt.Errorf("%s %q not found in local store. Run 'sync' first, or use the UUID directly", resourceType, input)
	case 1:
		return matches[0], nil
	default:
		hint := matches[0]
		if len(matches) > 5 {
			hint = strings.Join(matches[:5], ", ") + "..."
		} else {
			hint = strings.Join(matches, ", ")
		}
		return "", fmt.Errorf("ambiguous: %q matches %d %s entries (%s). Use the exact UUID instead", input, len(matches), resourceType, hint)
	}
}

// --- Typed helpers ---

// stringVal safely extracts a string from a map, returning "" if missing or wrong type.
func stringVal(obj map[string]any, key string) string {
	if v, ok := obj[key]; ok {
		switch s := v.(type) {
		case string:
			return s
		case float64:
			if s == float64(int64(s)) {
				return fmt.Sprintf("%d", int64(s))
			}
			return fmt.Sprintf("%g", s)
		default:
			return fmt.Sprintf("%v", v)
		}
	}
	return ""
}

// intVal safely extracts an integer from a map, returning 0 if missing or wrong type.
func intVal(obj map[string]any, key string) int64 {
	if v, ok := obj[key]; ok {
		switch n := v.(type) {
		case float64:
			return int64(n)
		case int:
			return int64(n)
		case int64:
			return n
		case json.Number:
			i, _ := n.Int64()
			return i
		case string:
			// try parse
			var i int64
			fmt.Sscanf(n, "%d", &i)
			return i
		}
	}
	return 0
}

// boolVal safely extracts a bool from a map, returning false if missing or wrong type.
func boolVal(obj map[string]any, key string) bool {
	if v, ok := obj[key]; ok {
		switch b := v.(type) {
		case bool:
			return b
		case float64:
			return b != 0
		case string:
			return b == "true" || b == "1"
		}
	}
	return false
}

// boolToInt converts a bool to 0 or 1 for SQLite storage.
func boolToInt(b bool) int {
	if b {
		return 1
	}
	return 0
}

// UpsertCollection inserts or updates a collection in the typed collections table.
func (s *Store) UpsertCollection(obj map[string]any) error {
	id := stringVal(obj, "id")
	if id == "" {
		return fmt.Errorf("collection missing id")
	}

	categoriesJSON := "[]"
	if cats, ok := obj["categories"]; ok {
		if b, err := json.Marshal(cats); err == nil {
			categoriesJSON = string(b)
		}
	}

	_, err := s.db.Exec(`INSERT INTO collections (
		id, name, slug, description, fork_count, watch_count, star_count,
		import_count, view_count, run_count, entity_type, categories,
		publisher_name, publisher_id, publisher_type, publisher_profile_url,
		is_public, is_published, is_favourite, is_official,
		summary, document_type, api_name, api_id, api_definition_id,
		created_at, updated_at, synced_at
	) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,CURRENT_TIMESTAMP)
	ON CONFLICT(id) DO UPDATE SET
		name=excluded.name, slug=excluded.slug, description=excluded.description,
		fork_count=excluded.fork_count, watch_count=excluded.watch_count,
		star_count=excluded.star_count, import_count=excluded.import_count,
		view_count=excluded.view_count, run_count=excluded.run_count,
		entity_type=excluded.entity_type, categories=excluded.categories,
		publisher_name=excluded.publisher_name, publisher_id=excluded.publisher_id,
		publisher_type=excluded.publisher_type, publisher_profile_url=excluded.publisher_profile_url,
		is_public=excluded.is_public, is_published=excluded.is_published,
		is_favourite=excluded.is_favourite, is_official=excluded.is_official,
		summary=excluded.summary, document_type=excluded.document_type,
		api_name=excluded.api_name, api_id=excluded.api_id,
		api_definition_id=excluded.api_definition_id,
		created_at=excluded.created_at, updated_at=excluded.updated_at,
		synced_at=CURRENT_TIMESTAMP`,
		id,
		stringVal(obj, "name"),
		stringVal(obj, "slug"),
		stringVal(obj, "description"),
		intVal(obj, "forkCount"),
		intVal(obj, "watchCount"),
		intVal(obj, "starCount"),
		intVal(obj, "importCount"),
		intVal(obj, "viewCount"),
		intVal(obj, "runCount"),
		stringVal(obj, "entityType"),
		categoriesJSON,
		stringVal(obj, "publisherName"),
		stringVal(obj, "publisherId"),
		stringVal(obj, "publisherType"),
		stringVal(obj, "publisherProfileUrl"),
		boolToInt(boolVal(obj, "isPublic")),
		boolToInt(boolVal(obj, "isPublished")),
		boolToInt(boolVal(obj, "isFavourite")),
		boolToInt(boolVal(obj, "isOfficial")),
		stringVal(obj, "summary"),
		stringVal(obj, "documentType"),
		stringVal(obj, "apiName"),
		stringVal(obj, "apiId"),
		stringVal(obj, "apiDefinitionId"),
		stringVal(obj, "createdAt"),
		stringVal(obj, "updatedAt"),
	)
	if err != nil {
		return fmt.Errorf("upserting collection %s: %w", id, err)
	}

	// Update FTS index
	_, _ = s.db.Exec(`DELETE FROM collections_fts WHERE id = ?`, id)
	_, _ = s.db.Exec(
		`INSERT INTO collections_fts (id, name, description, summary, publisher_name, api_name)
		 VALUES (?, ?, ?, ?, ?, ?)`,
		id,
		stringVal(obj, "name"),
		stringVal(obj, "description"),
		stringVal(obj, "summary"),
		stringVal(obj, "publisherName"),
		stringVal(obj, "apiName"),
	)

	return nil
}

